// OAuth 2.1 Client Credentials Flow - Token Request Processing (Fixed)
try {
    // Input von Webhook Node
    const requestBody = $('Webhook OAuth Token').first().json.body || {};
    const requestHeaders = $('Webhook OAuth Token').first().json.headers || {};

    const { grant_type, client_id, client_secret, scope } = requestBody;

    console.log('OAuth Token Request:', { grant_type, client_id, scope });

    // Validierung des Grant Types
    if (grant_type !== 'client_credentials') {
        return [{
            json: {
                error: 'unsupported_grant_type',
                error_description: 'Only client_credentials grant type is supported',
                valid_grant_types: ['client_credentials'],
                statusCode: 400,
                isError: true
            }
        }];
    }

    // Prüfe ob alle erforderlichen Parameter vorhanden sind
    if (!client_id || !client_secret) {
        return [{
            json: {
                error: 'invalid_request',
                error_description: 'Missing required parameters: client_id and client_secret',
                statusCode: 400,
                isError: true
            }
        }];
    }

    // Environment Variables laden
    const jwtSecret = $env.JWT_SECRET;
    const issuer = $env.OAUTH_ISSUER || 'https://oauth.srv768465.hstgr.cloud';
    const audience = $env.OAUTH_AUDIENCE || 'mcp-api';

    // Basis-Validierung der Environment Variables
    if (!jwtSecret) {
        return [{
            json: {
                error: 'server_error',
                error_description: 'OAuth server configuration incomplete',
                statusCode: 500,
                isError: true
            }
        }];
    }

    // Erfolgreiche Vorbereitung für Client-Validation
    return [{
        json: {
            client_id,
            client_secret,
            scope: scope || 'mcp:read mcp:execute',
            jwtSecret,
            issuer,
            audience,
            grant_type,
            request_time: new Date().toISOString(),
            statusCode: 200,
            isError: false
        }
    }];

} catch (error) {
    console.error('OAuth Token Processing Error:', error);
    return [{
        json: {
            error: 'server_error',
            error_description: 'Internal processing error: ' + error.message,
            statusCode: 500,
            isError: true
        }
    }];
}

// JWT Token Generation für OAuth 2.1 (Fixed)
const crypto = require('crypto');

try {
    // Input von vorherigen Nodes
    const clientValidation = $('Validate Client').first().json || [];
    const tokenRequest = $('Process Token Request').first().json;

    // Prüfe ob vorheriger Node einen Fehler hatte
    if (tokenRequest.isError) {
        return [{
            json: tokenRequest  // Fehler weiterleiten
        }];
    }

    console.log('Client Validation Result:', clientValidation.length, 'clients found');

    // Client existiert nicht oder invalid
    if (!clientValidation || clientValidation.length === 0) {
        return [{
            json: {
                error: 'invalid_client',
                error_description: 'Invalid client credentials or client not found',
                statusCode: 401,
                isError: true
            }
        }];
    }

    const client = clientValidation[0];
    const requestedScopes = tokenRequest.scope.split(' ');

    // Scope-Validierung
    const clientScopes = client.scopes || [];
    const validScopes = requestedScopes.filter(scope => 
        clientScopes.includes(scope) || scope === 'mcp:read'
    );

    // Default Scope falls keine validen Scopes
    if (validScopes.length === 0) {
        validScopes.push('mcp:read');
    }

    console.log('Granted Scopes:', validScopes);

    // JWT Header
    const header = {
        alg: 'HS256',
        typ: 'JWT',
        kid: 'oauth-server-key-1'
    };

    // JWT Payload
    const now = Math.floor(Date.now() / 1000);
    const tokenId = crypto.randomUUID();

    const payload = {
        iss: tokenRequest.issuer,
        aud: tokenRequest.audience,
        sub: client.client_id,
        client_id: client.client_id,
        client_name: client.client_name,
        scope: validScopes.join(' '),
        iat: now,
        exp: now + (24 * 60 * 60), // 24 Stunden
        nbf: now,
        jti: tokenId,
        token_type: 'access_token'
    };

    console.log('JWT Payload created for client:', client.client_id);

    // JWT signieren
    const headerB64 = Buffer.from(JSON.stringify(header)).toString('base64url');
    const payloadB64 = Buffer.from(JSON.stringify(payload)).toString('base64url');
    const signatureInput = `${headerB64}.${payloadB64}`;

    const signature = crypto
        .createHmac('sha256', tokenRequest.jwtSecret)
        .update(signatureInput)
        .digest('base64url');

    const accessToken = `${headerB64}.${payloadB64}.${signature}`;

    // Success Response
    return [{
        json: {
            access_token: accessToken,
            token_type: 'Bearer',
            expires_in: 86400, // 24 Stunden
            scope: validScopes.join(' '),
            client_id: client.client_id,
            client_name: client.client_name,
            issued_at: now,
            expires_at: new Date((now + 86400) * 1000).toISOString(),
            token_id: tokenId,
            db_scopes: validScopes,
            statusCode: 200,
            isError: false
        }
    }];

} catch (error) {
    console.error('JWT Generation Error:', error);
    return [{
        json: {
            error: 'server_error',
            error_description: 'Token generation failed: ' + error.message,
            statusCode: 500,
            isError: true
        }
    }];
}

