// Response Handler für OAuth-Workflow (Fixed)
try {
    const input = $input.first().json;

    // Prüfe ob es ein Fehler-Response ist
    if (input.isError || input.error) {
        console.error('OAuth Error:', input.error, input.error_description);

        // HTTP Status über $execution setzen für Webhook Response
        $execution.setCurrentExecutionData({
            http: {
                statusCode: input.statusCode || 400,
                headers: {
                    'Content-Type': 'application/json',
                    'Cache-Control': 'no-store',
                    'Pragma': 'no-cache'
                }
            }
        });

        return [{
            json: {
                error: input.error,
                error_description: input.error_description,
                timestamp: new Date().toISOString(),
                request_id: $('Webhook OAuth Token').first().json.headers['x-request-id'] || 'unknown'
            }
        }];
    }

    // Success Response
    const tokenData = $('Store Token').first().json[0] || {};
    const jwtResponse = input;

    console.log('OAuth Token issued successfully for client:', jwtResponse.client_id);

    // HTTP Status für Success setzen
    $execution.setCurrentExecutionData({
        http: {
            statusCode: 200,
            headers: {
                'Content-Type': 'application/json',
                'Cache-Control': 'no-store',
                'Pragma': 'no-cache',
                'X-Token-ID': tokenData.token_id || 'unknown'
            }
        }
    });

    return [{
        json: {
            access_token: jwtResponse.access_token,
            token_type: jwtResponse.token_type,
            expires_in: jwtResponse.expires_in,
            scope: jwtResponse.scope,
            issued_at: jwtResponse.issued_at,
            token_id: tokenData.token_id
        }
    }];

} catch (error) {
    console.error('Response Handler Error:', error);

    $execution.setCurrentExecutionData({
        http: {
            statusCode: 500,
            headers: {
